patch:
--- a/counter.v
+++ b/counter.v
@@ -1,9 +1,10 @@
 module counter_16(
   input clk,
   input reset,
+  input enable,
   output [15:0] count
 );
   reg [15:0] cnt;
   always @(posedge clk) begin
     if(reset)
       cnt <= 16'b0;
+    else if(enable)
       cnt <= cnt + 1'b1;
   end
   assign count = cnt;
@@ -11,5 +12,5 @@ module counter_16(

 module wrapper(
   input clk, rst, en,
   output [15:0] out
 );
-  counter_16 c1(.clk(clk), .reset(rst), .count(out));
+  counter_16 c1(.clk(clk), .reset(rst), .enable(en), .count(out));
 endmodule

before_code:
module counter_16(
  input clk,
  input reset,
  output [15:0] count
);
  reg [15:0] cnt;
  always @(posedge clk) begin
    if(reset)
      cnt <= 16'b0;
    cnt <= cnt + 1'b1;
  end
  assign count = cnt;
endmodule

module wrapper(
  input clk, rst, en,
  output [15:0] out
);
  counter_16 c1(.clk(clk), .reset(rst), .count(out));
endmodule

after_code:
module counter_16(
  input clk,
  input reset,
  input enable,
  output [15:0] count
);
  reg [15:0] cnt;
  always @(posedge clk) begin
    if(reset)
      cnt <= 16'b0;
    else if(enable)
      cnt <= cnt + 1'b1;
  end
  assign count = cnt;
endmodule

module wrapper(
  input clk, rst, en,
  output [15:0] out
);
  counter_16 c1(.clk(clk), .reset(rst), .enable(en), .count(out));
endmodule
